def write(name, text):
    p = PKG / name
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(text, encoding="utf-8")

CONFIG = '# -*- coding: utf-8 -*-\nfrom pathlib import Path\n\nBASE_DIR = Path(r"C:\\Users\\MSI\\Desktop\\kik_proje")\nPY_DIR = BASE_DIR / ".py"\nSTATE_DIR = BASE_DIR / "production_state"\nREPORT_DIR = BASE_DIR / "raporlar"\nSCHEDULER_DIR = STATE_DIR / "scheduler"\n\nSCHEDULER_REGISTRY_FILE = SCHEDULER_DIR / "202_scheduler_registry.json"\nSCHEDULER_HISTORY_FILE = SCHEDULER_DIR / "202_scheduler_history.jsonl"\n\nPLATFORM_CORE = PY_DIR / "200_Platform.py"\nEVENT_BUS = PY_DIR / "201_v1_Event_Bus.py"\nEVENT_PUBLISHER = PY_DIR / "201_v2_Event_Publisher_Integration.py"\nEVENT_AUDITOR = PY_DIR / "201_v3_Event_Bus_Viewer_Auditor.py"\n\nDEFAULT_JOBS = [\n    {\n        "job_id": "SCHED-HEALTH-DAILY",\n        "name": "Daily Platform Health",\n        "enabled": True,\n        "schedule": "daily",\n        "action": "platform_health",\n        "command": \'python ".py\\\\200_Platform.py" --status\',\n        "priority": 1,\n        "notes": "Platform sağlık kontrolü."\n    },\n    {\n        "job_id": "SCHED-EVENT-PUBLISH",\n        "name": "Event Publisher",\n        "enabled": True,\n        "schedule": "manual",\n        "action": "event_publish",\n        "command": \'python ".py\\\\201_v2_Event_Publisher_Integration.py" --publish\',\n        "priority": 2,\n        "notes": "Son state dosyalarını Event Bus\'a işler."\n    },\n    {\n        "job_id": "SCHED-EVENT-AUDIT",\n        "name": "Event Audit",\n        "enabled": True,\n        "schedule": "manual",\n        "action": "event_audit",\n        "command": \'python ".py\\\\201_v3_Event_Bus_Viewer_Auditor.py" --tail=20\',\n        "priority": 3,\n        "notes": "Event Bus audit raporu üretir."\n    },\n    {\n        "job_id": "SCHED-RECOVERY-CHECK",\n        "name": "Recovery Check",\n        "enabled": True,\n        "schedule": "manual",\n        "action": "recovery_check",\n        "command": \'python ".py\\\\197_v4_Recovery_Manager_Completed_Run_Aware.py"\',\n        "priority": 4,\n        "notes": "Recovery durumunu kontrol eder."\n    }\n]\n'

UTILS = '# -*- coding: utf-8 -*-\nimport json\nimport shutil\nfrom pathlib import Path\nfrom datetime import datetime\n\ndef now_stamp():\n    return datetime.now().strftime("%Y%m%d_%H%M%S")\n\ndef now_text():\n    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")\n\ndef ensure_dirs(*dirs):\n    for d in dirs:\n        Path(d).mkdir(parents=True, exist_ok=True)\n\ndef disk_free_gb(path):\n    usage = shutil.disk_usage(str(path))\n    return round(usage.free / (1024 ** 3), 2)\n\ndef safe_read(path, limit_chars=500000):\n    path = Path(path)\n    if not path.exists():\n        return ""\n    for enc in ("utf-8", "utf-8-sig", "cp1254", "latin-1"):\n        try:\n            return path.read_text(encoding=enc, errors="ignore")[:limit_chars]\n        except Exception:\n            pass\n    return ""\n\ndef safe_json(path):\n    path = Path(path)\n    if not path.exists():\n        return None\n    try:\n        return json.loads(safe_read(path))\n    except Exception:\n        return None\n\ndef write_json(path, data):\n    path = Path(path)\n    path.parent.mkdir(parents=True, exist_ok=True)\n    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")\n'

REGISTRY = '# -*- coding: utf-8 -*-\nfrom config import BASE_DIR, STATE_DIR, REPORT_DIR, SCHEDULER_DIR, SCHEDULER_REGISTRY_FILE, DEFAULT_JOBS\nfrom utils import now_text, now_stamp, ensure_dirs, write_json, safe_json, disk_free_gb\n\ndef load_registry():\n    data = safe_json(SCHEDULER_REGISTRY_FILE)\n    if data:\n        return data, False\n    return create_registry()\n\ndef create_registry():\n    ensure_dirs(STATE_DIR, REPORT_DIR, SCHEDULER_DIR)\n    registry = {\n        "module": "202 Platform Scheduler Registry",\n        "created_at": now_text(),\n        "updated_at": now_text(),\n        "version": "v1",\n        "jobs": DEFAULT_JOBS,\n    }\n    write_json(SCHEDULER_REGISTRY_FILE, registry)\n    return registry, True\n\ndef validate(registry):\n    errors = []\n    warnings = []\n    jobs = registry.get("jobs", []) if registry else []\n\n    seen = set()\n    for job in jobs:\n        jid = job.get("job_id")\n        if not jid:\n            errors.append("job_id eksik görev var.")\n            continue\n        if jid in seen:\n            errors.append(f"Duplicate job_id: {jid}")\n        seen.add(jid)\n\n        if job.get("schedule") not in ("manual", "hourly", "daily", "weekly"):\n            errors.append(f"{jid}: geçersiz schedule: {job.get(\'schedule\')}")\n\n        if not job.get("command"):\n            warnings.append(f"{jid}: command boş.")\n\n        if not isinstance(job.get("enabled"), bool):\n            warnings.append(f"{jid}: enabled boolean değil.")\n\n    if not jobs:\n        errors.append("Scheduler job registry boş.")\n\n    score = 100 - min(60, len(errors) * 15) - min(30, len(warnings) * 3)\n    score = max(0, score)\n    decision = "SCHEDULER REGISTRY INVALID" if errors else ("SCHEDULER REGISTRY REVIEW" if warnings else "SCHEDULER REGISTRY READY")\n    return {"score": score, "decision": decision, "errors": errors, "warnings": warnings}\n\ndef run(init=False, force=False):\n    ensure_dirs(STATE_DIR, REPORT_DIR, SCHEDULER_DIR)\n    ts = now_stamp()\n\n    if init or force or not SCHEDULER_REGISTRY_FILE.exists():\n        registry, created = create_registry()\n    else:\n        registry, created = load_registry()\n\n    result = validate(registry)\n    state = STATE_DIR / f"202_pkg_registry_state_{ts}.json"\n    report = REPORT_DIR / f"202_pkg_registry_raporu_{ts}.txt"\n\n    payload = {\n        "module": "202 Package Scheduler Registry",\n        "created_at": now_text(),\n        "registry_file": str(SCHEDULER_REGISTRY_FILE),\n        "created_now": created,\n        "disk_free_gb": disk_free_gb(BASE_DIR),\n        "registry": registry,\n        "result": result,\n    }\n    write_json(state, payload)\n\n    jobs = registry.get("jobs", [])\n    enabled = sum(1 for j in jobs if j.get("enabled") is True)\n    report.write_text("\\n".join([\n        "="*80,\n        "202 PACKAGE - SCHEDULER REGISTRY",\n        "="*80,\n        f"Score      : {result[\'score\']} / 100",\n        f"Decision   : {result[\'decision\']}",\n        f"Jobs       : {len(jobs)}",\n        f"Enabled    : {enabled}",\n        f"Created    : {created}",\n        "",\n        "JOBS",\n        "-"*80,\n        *[f"{j.get(\'job_id\'):<24} | {j.get(\'schedule\'):<8} | enabled={j.get(\'enabled\')} | {j.get(\'action\')}" for j in jobs],\n        "",\n        "Dosyalar:",\n        str(SCHEDULER_REGISTRY_FILE),\n        str(state),\n        str(report),\n    ]), encoding="utf-8")\n\n    return {"registry": registry, "result": result, "paths": {"registry": str(SCHEDULER_REGISTRY_FILE), "state": str(state), "report": str(report)}}\n'

HISTORY = '# -*- coding: utf-8 -*-\nimport json\nfrom config import STATE_DIR, REPORT_DIR, SCHEDULER_DIR, SCHEDULER_HISTORY_FILE\nfrom utils import now_text, now_stamp, ensure_dirs, write_json, safe_read\n\ndef append_history(record):\n    ensure_dirs(STATE_DIR, REPORT_DIR, SCHEDULER_DIR)\n    record["created_at"] = now_text()\n    with SCHEDULER_HISTORY_FILE.open("a", encoding="utf-8") as f:\n        f.write(json.dumps(record, ensure_ascii=False) + "\\n")\n\ndef read_history(limit=50):\n    ensure_dirs(STATE_DIR, REPORT_DIR, SCHEDULER_DIR)\n    if not SCHEDULER_HISTORY_FILE.exists():\n        return []\n    lines = safe_read(SCHEDULER_HISTORY_FILE).splitlines()\n    events = []\n    for line in lines[-limit:]:\n        try:\n            events.append(json.loads(line))\n        except Exception:\n            events.append({"status":"INVALID_LINE","raw":line[:300]})\n    return events\n\ndef run(limit=50):\n    ensure_dirs(STATE_DIR, REPORT_DIR, SCHEDULER_DIR)\n    ts = now_stamp()\n    events = read_history(limit=limit)\n    invalid = sum(1 for e in events if e.get("status") == "INVALID_LINE")\n    result = {"score": 100 if invalid == 0 else 80, "decision": "SCHEDULER HISTORY READY" if invalid == 0 else "SCHEDULER HISTORY REVIEW", "errors": [], "warnings": []}\n    state = STATE_DIR / f"202_pkg_history_state_{ts}.json"\n    report = REPORT_DIR / f"202_pkg_history_raporu_{ts}.txt"\n    payload = {"module":"202 Scheduler History","created_at":now_text(),"history_file":str(SCHEDULER_HISTORY_FILE),"events":events,"result":result}\n    write_json(state, payload)\n    report.write_text("\\n".join([\n        "="*80,\n        "202 PACKAGE - SCHEDULER HISTORY",\n        "="*80,\n        f"Score    : {result[\'score\']} / 100",\n        f"Decision : {result[\'decision\']}",\n        f"Events   : {len(events)}",\n        f"Invalid  : {invalid}",\n        "",\n        "Dosyalar:",\n        str(SCHEDULER_HISTORY_FILE),\n        str(state),\n        str(report),\n    ]), encoding="utf-8")\n    return {"events": events, "result": result, "paths": {"history": str(SCHEDULER_HISTORY_FILE), "state": str(state), "report": str(report)}}\n'

SCHEDULER = '# -*- coding: utf-8 -*-\nfrom registry import run as run_registry\nfrom history import append_history\nfrom utils import now_text\n\ndef plan():\n    reg = run_registry(init=False)\n    jobs = reg["registry"].get("jobs", [])\n    enabled_jobs = [j for j in jobs if j.get("enabled") is True]\n    result = {\n        "score": 100 if reg["result"]["decision"] == "SCHEDULER REGISTRY READY" else 85,\n        "decision": "SCHEDULER PLAN READY",\n        "errors": [],\n        "warnings": [],\n    }\n    return {"jobs": jobs, "enabled_jobs": enabled_jobs, "registry_result": reg["result"], "result": result}\n\ndef record_plan():\n    p = plan()\n    append_history({\n        "event": "SchedulerPlanCreated",\n        "status": "PASS",\n        "enabled_jobs": len(p["enabled_jobs"]),\n        "total_jobs": len(p["jobs"]),\n        "time": now_text(),\n    })\n    return p\n'

MANAGER = '# -*- coding: utf-8 -*-\nimport argparse\nfrom registry import run as run_registry\nfrom history import run as run_history\nfrom scheduler import record_plan\n\ndef main():\n    parser = argparse.ArgumentParser()\n    parser.add_argument("--init", action="store_true")\n    parser.add_argument("--status", action="store_true")\n    parser.add_argument("--plan", action="store_true")\n    parser.add_argument("--history", action="store_true")\n    args = parser.parse_args()\n\n    if args.history:\n        h = run_history()\n        print("="*80)\n        print("202 PACKAGE HISTORY TAMAMLANDI")\n        print("="*80)\n        print(f"Decision : {h[\'result\'][\'decision\']} ({h[\'result\'][\'score\']}/100)")\n        print(h["paths"]["report"])\n        return\n\n    if args.plan:\n        p = record_plan()\n        print("="*80)\n        print("202 PACKAGE SCHEDULER PLAN TAMAMLANDI")\n        print("="*80)\n        print(f"Decision     : {p[\'result\'][\'decision\']} ({p[\'result\'][\'score\']}/100)")\n        print(f"Total Jobs   : {len(p[\'jobs\'])}")\n        print(f"Enabled Jobs : {len(p[\'enabled_jobs\'])}")\n        return\n\n    r = run_registry(init=args.init)\n    print("="*80)\n    print("202 PACKAGE SCHEDULER TAMAMLANDI")\n    print("="*80)\n    print(f"Decision : {r[\'result\'][\'decision\']} ({r[\'result\'][\'score\']}/100)")\n    print(f"Jobs     : {len(r[\'registry\'].get(\'jobs\', []))}")\n    print("")\n    print("Dosyalar:")\n    print(r["paths"]["registry"])\n    print(r["paths"]["report"])\n\nif __name__ == "__main__":\n    main()\n'

BRIDGE = '# -*- coding: utf-8 -*-\nimport sys\nfrom pathlib import Path\nPACKAGE_DIR = Path(__file__).resolve().parent / "202"\nsys.path.insert(0, str(PACKAGE_DIR))\nfrom manager import main\nif __name__ == "__main__":\n    main()\n'

README = '# 202 Platform Scheduler Package\n\nNeoLegal Production Platform v2.0 için görev zamanlayıcı paketidir.\n\nİlk sürüm production çalıştırmaz.\n\nKomutlar:\npython ".py\\202_Platform_Scheduler.py" --init\npython ".py\\202_Platform_Scheduler.py" --status\npython ".py\\202_Platform_Scheduler.py" --plan\npython ".py\\202_Platform_Scheduler.py" --history\n'

