    write("manager.py", MANAGER)

    (PY / "202_Platform_Scheduler.py").write_text(BRIDGE, encoding="utf-8")

    print("="*80)
    print("202 PACKAGE INSTALLER TAMAMLANDI")
    print("="*80)
    print("Kurulan klasör:")
    print(PKG)
    print("")
    print("Şimdi çalıştır:")
    print(r'cd /d C:\Users\MSI\Desktop\kik_proje')
    print(r'python ".py\202_Platform_Scheduler.py" --init')

